"""matplotlib.transforms — coordinate transform stubs."""

import numpy as _np


class Transform:
    """Base transform."""
    input_dims = 2
    output_dims = 2
    is_affine = True

    def transform(self, values):
        return _np.asarray(values)

    def inverted(self):
        return self

    def __add__(self, other):
        return self

    def __sub__(self, other):
        return self


class Affine2D(Transform):
    def __init__(self, matrix=None):
        self._mtx = matrix if matrix is not None else _np.eye(3)

    def rotate(self, theta):
        return self

    def rotate_deg(self, degrees):
        return self

    def translate(self, tx, ty):
        return self

    def scale(self, sx, sy=None):
        return self

    @staticmethod
    def identity():
        return Affine2D()

    def get_matrix(self):
        return self._mtx


class BboxBase:
    pass


class Bbox(BboxBase):
    def __init__(self, points):
        self._points = _np.asarray(points)

    @staticmethod
    def from_bounds(x0, y0, width, height):
        return Bbox([[x0, y0], [x0 + width, y0 + height]])

    @staticmethod
    def from_extents(x0, y0, x1, y1):
        return Bbox([[x0, y0], [x1, y1]])

    @property
    def x0(self): return self._points[0, 0]
    @property
    def y0(self): return self._points[0, 1]
    @property
    def x1(self): return self._points[1, 0]
    @property
    def y1(self): return self._points[1, 1]
    @property
    def width(self): return self.x1 - self.x0
    @property
    def height(self): return self.y1 - self.y0

    def transformed(self, transform):
        return self

    def expanded(self, sw, sh):
        return self


class TransformedBbox(BboxBase):
    def __init__(self, bbox, transform):
        self._bbox = bbox
        self._transform = transform


class BlendedGenericTransform(Transform):
    def __init__(self, x_transform, y_transform):
        self._x = x_transform
        self._y = y_transform


class CompositeGenericTransform(Transform):
    def __init__(self, a, b):
        self._a = a
        self._b = b


def blended_transform_factory(x_transform, y_transform):
    return BlendedGenericTransform(x_transform, y_transform)


class ScaledTranslation(Transform):
    def __init__(self, xt, yt, scale_trans):
        self._xt = xt
        self._yt = yt


class IdentityTransform(Transform):
    pass
